/* 在HTML的<head>里加 <link rel="stylesheet" href="style.css"> 引入此文件 */

/* 全局基础设置 */
* {
  box-sizing: border-box; /* 让宽高计算更直观 */
}

body {
  font-family: 'Microsoft YaHei', sans-serif;
  background: linear-gradient(135deg, #1a1a2e, #16213e);
  color: #eee;
  min-height: 100vh;
}

/* 卡片组件 */
.card {
  background: rgba(255,255,255,0.05);
  border: 1px solid rgba(255,255,255,0.1);
  border-radius: 12px;
  padding: 24px;
  /* hover动画：鼠标悬停时上浮 */
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.card:hover {
  transform: translateY(-6px);
  box-shadow: 0 20px 40px rgba(0,0,0,0.4);
}

/* 渐变文字标题 */
.title {
  background: linear-gradient(90deg, #4fc3f7, #7c4dff);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  font-size: 2rem;
  font-weight: 800;
}

// === 基础：操作页面元素 ===
const title = document.querySelector('h1'); // 找到h1标签
title.textContent = '内容被JS动态修改了！'; // 改变文字
title.style.color = '#4fc3f7'; // 改变颜色

// === 事件监听：响应用户操作 ===
const btn = document.getElementById('myBtn');
btn.addEventListener('click', function() {
  alert('你点击了按钮！');
});

// === 定时器：每隔一秒执行一次 ===
let count = 0;
setInterval(() => {
  count++;
  document.getElementById('counter').textContent = `已运行 ${count} 秒`;
}, 1000);

// === Fetch API：从服务器获取数据（不刷新页面！）===
async function loadUserInfo() {
  const response = await fetch('/api/user/123'); // 发网络请求
  const user = await response.json(); // 解析JSON格式数据
  document.getElementById('username').textContent = user.name;
}
loadUserInfo();
